     1→import { Router, Request, Response } from 'express';
     2→import { prisma } from '../db/prisma';
     3→import { ChannelVisibility } from '@prisma/client';
     4→import { cacheMiddleware } from '../middleware/cache.middleware';
     5→import { cacheService, CacheKeys, CacheTTL, sanitizeKeySegment } from '../services/cache.service';
     6→import { tokenBucketRateLimiter } from '../middleware/rate-limit.middleware';
     7→
     8→export const publicRouter = Router();
     9→
    10→// Token bucket rate limiting per issue #110: 100 req/min (human) / 1000 req/min (verified bots)
    11→publicRouter.use(tokenBucketRateLimiter);
    12→
    13→/**
    14→ * GET /api/public/channels/:channelId/messages
    15→ * Returns paginated messages for a PUBLIC_INDEXABLE channel.
    16→ * Uses cache middleware with stale-while-revalidate.
    17→ */
    18→publicRouter.get(
    19→  '/channels/:channelId/messages',
    20→  cacheMiddleware({
    21→    ttl: CacheTTL.channelMessages,
    22→    staleTtl: CacheTTL.channelMessages, // keep stale data for an extra TTL window
    23→    keyFn: (req: Request) => CacheKeys.channelMessages(req.params.channelId, Number(req.query.page) || 1),
    24→  }),
    25→  async (req: Request, res: Response) => {
    26→    try {
    27→      const { channelId } = req.params;
    28→      const page = Math.max(1, Number(req.query.page) || 1);
    29→      const pageSize = 50;
    30→
    31→      const channel = await prisma.channel.findUnique({
    32→        where: { id: channelId },
    33→        select: { id: true, visibility: true },
    34→      });
    35→
    36→      if (!channel || channel.visibility !== ChannelVisibility.PUBLIC_INDEXABLE) {
    37→        res.status(404).json({ error: 'Channel not found' });
    38→        return;
    39→      }
    40→
    41→      const messages = await prisma.message.findMany({
    42→        where: { channelId, isDeleted: false },
    43→        orderBy: { createdAt: 'desc' },
    44→        skip: (page - 1) * pageSize,
    45→        take: pageSize,
    46→        select: {
    47→          id: true,
    48→          content: true,
    49→          createdAt: true,
    50→          editedAt: true,
    51→          author: { select: { id: true, username: true } },
    52→        },
    53→      });
    54→
    55→      res.set('Cache-Control', `public, max-age=${CacheTTL.channelMessages}`);
    56→      res.json({ messages, page, pageSize });
    57→    } catch (err) {
    58→      console.error('Public messages route error:', err);
    59→      if (!res.headersSent) {
    60→        res.status(500).json({ error: 'Internal server error' });
    61→      }
    62→    }
    63→  },
    64→);
    65→
    66→/**
    67→ * GET /api/public/channels/:channelId/messages/:messageId
    68→ * Returns a single message from a PUBLIC_INDEXABLE channel.
    69→ * Uses cache middleware with stale-while-revalidate.
    70→ */
    71→publicRouter.get(
    72→  '/channels/:channelId/messages/:messageId',
    73→  cacheMiddleware({
    74→    ttl: CacheTTL.channelMessages,
    75→    staleTtl: CacheTTL.channelMessages,
    76→    keyFn: (req: Request) => `channel:msg:${sanitizeKeySegment(req.params.channelId)}:${sanitizeKeySegment(req.params.messageId)}`,
    77→  }),
    78→  async (req: Request, res: Response) => {
    79→    try {
    80→      const { channelId, messageId } = req.params;
    81→
    82→      const channel = await prisma.channel.findUnique({
    83→        where: { id: channelId },
    84→        select: { id: true, visibility: true },
    85→      });
    86→
    87→      if (!channel || channel.visibility !== ChannelVisibility.PUBLIC_INDEXABLE) {
    88→        res.status(404).json({ error: 'Channel not found' });
    89→        return;
    90→      }
    91→
    92→      const message = await prisma.message.findFirst({
    93→        where: { id: messageId, channelId, isDeleted: false },
    94→        select: {
    95→          id: true,
    96→          content: true,
    97→          createdAt: true,
    98→          editedAt: true,
    99→          author: { select: { id: true, username: true } },
   100→        },
   101→      });
   102→
   103→      if (!message) {
   104→        res.status(404).json({ error: 'Message not found' });
   105→        return;
   106→      }
   107→
   108→      res.set('Cache-Control', `public, max-age=${CacheTTL.channelMessages}`);
   109→      res.json(message);
   110→    } catch (err) {
   111→      console.error('Public message route error:', err);
   112→      if (!res.headersSent) {
   113→        res.status(500).json({ error: 'Internal server error' });
   114→      }
   115→    }
   116→  },
   117→);
   118→
   119→/**
   120→ * GET /api/public/servers/:serverSlug
   121→ * Returns public server info. Uses getOrRevalidate for SWR.
   122→ * Cache key: server:{serverId}:info per §4.4.
   123→ */
   124→publicRouter.get(
   125→  '/servers/:serverSlug',
   126→  async (req: Request, res: Response) => {
   127→    try {
   128→      const server = await prisma.server.findUnique({
   129→        where: { slug: req.params.serverSlug },
   130→        select: { id: true, name: true, slug: true, iconUrl: true, description: true, memberCount: true, createdAt: true },
   131→      });
   132→
   133→      if (!server) {
   134→        res.status(404).json({ error: 'Server not found' });
   135→        return;
   136→      }
   137→
   138→      const cacheKey = CacheKeys.serverInfo(server.id);
   139→      const cacheOpts = { ttl: CacheTTL.serverInfo, staleTtl: CacheTTL.serverInfo };
   140→
   141→      // Check cache state for X-Cache header
   142→      let xCache = 'MISS';
   143→      try {
   144→        const entry = await cacheService.get(cacheKey);
   145→        if (entry) {
   146→          xCache = cacheService.isStale(entry, CacheTTL.serverInfo) ? 'STALE' : 'HIT';
   147→        }
   148→      } catch { /* Redis error */ }
   149→
   150→      const data = await cacheService.getOrRevalidate(
   151→        cacheKey,
   152→        async () => server, // fetcher — server already fetched from DB above
   153→        cacheOpts,
   154→      );
   155→
   156→      res.set('X-Cache', xCache);
   157→      res.set('X-Cache-Key', cacheKey);
   158→      res.set('Cache-Control', `public, max-age=${CacheTTL.serverInfo}`);
   159→      res.json(data);
   160→    } catch (err) {
   161→      console.error('Public server route error:', err);
   162→      res.status(500).json({ error: 'Internal server error' });
   163→    }
   164→  },
   165→);
   166→
   167→/**
   168→ * GET /api/public/servers/:serverSlug/channels
   169→ * Returns public channels for a server. Uses getOrRevalidate for SWR.
   170→ * Cache key: server:{serverId}:public_channels per §4.4.
   171→ */
   172→publicRouter.get(
   173→  '/servers/:serverSlug/channels',
   174→  async (req: Request, res: Response) => {
   175→    try {
   176→      const server = await prisma.server.findUnique({
   177→        where: { slug: req.params.serverSlug },
   178→        select: { id: true },
   179→      });
   180→
   181→      if (!server) {
   182→        res.status(404).json({ error: 'Server not found' });
   183→        return;
   184→      }
   185→
   186→      const cacheKey = `server:${sanitizeKeySegment(server.id)}:public_channels`;
   187→      const cacheOpts = { ttl: CacheTTL.serverInfo, staleTtl: CacheTTL.serverInfo };
   188→
   189→      const fetcher = async () => {
   190→        const channels = await prisma.channel.findMany({
   191→          where: { serverId: server.id, visibility: ChannelVisibility.PUBLIC_INDEXABLE },
   192→          orderBy: { position: 'asc' },
   193→          select: { id: true, name: true, slug: true, type: true, topic: true },
   194→        });
   195→        return { channels };
   196→      };
   197→
   198→      // Check cache state for X-Cache header
   199→      let xCache = 'MISS';
   200→      try {
   201→        const entry = await cacheService.get(cacheKey);
   202→        if (entry) {
   203→          xCache = cacheService.isStale(entry, CacheTTL.serverInfo) ? 'STALE' : 'HIT';
   204→        }
   205→      } catch { /* Redis error */ }
   206→
   207→      const data = await cacheService.getOrRevalidate(cacheKey, fetcher, cacheOpts);
   208→
   209→      res.set('X-Cache', xCache);
   210→      res.set('X-Cache-Key', cacheKey);
   211→      res.set('Cache-Control', `public, max-age=${CacheTTL.serverInfo}`);
   212→      res.json(data);
   213→    } catch (err) {
   214→      console.error('Public channels route error:', err);
   215→      res.status(500).json({ error: 'Internal server error' });
   216→    }
   217→  },
   218→);
   219→

