     1→import axios, { type AxiosInstance, type AxiosRequestConfig, type InternalAxiosRequestConfig } from 'axios';
     2→import { API_CONFIG } from './constants';
     3→
     4→// ─── Token storage ────────────────────────────────────────────────────────────
     5→// Access token is kept only in module-level memory (never persisted) so it is
     6→// cleared on page refresh and cannot be read by injected scripts via localStorage.
     7→// Refresh token is stored in localStorage so users stay logged-in across reloads.
     8→
     9→const REFRESH_TOKEN_KEY = 'harmony_refresh_token';
    10→
    11→let _accessToken: string | null = null;
    12→let _isRefreshing = false;
    13→let _refreshQueue: Array<(token: string | null) => void> = [];
    14→
    15→function notifyRefreshQueue(token: string | null) {
    16→  _refreshQueue.forEach(resolve => resolve(token));
    17→  _refreshQueue = [];
    18→}
    19→
    20→export function setTokens(accessToken: string, refreshToken: string): void {
    21→  _accessToken = accessToken;
    22→  if (typeof window !== 'undefined') {
    23→    localStorage.setItem(REFRESH_TOKEN_KEY, refreshToken);
    24→  }
    25→}
    26→
    27→export function clearTokens(): void {
    28→  _accessToken = null;
    29→  if (typeof window !== 'undefined') {
    30→    localStorage.removeItem(REFRESH_TOKEN_KEY);
    31→  }
    32→}
    33→
    34→export function getAccessToken(): string | null {
    35→  return _accessToken;
    36→}
    37→
    38→export function getRefreshToken(): string | null {
    39→  if (typeof window === 'undefined') return null;
    40→  return localStorage.getItem(REFRESH_TOKEN_KEY);
    41→}
    42→
    43→// ─── tRPC HTTP helpers ────────────────────────────────────────────────────────
    44→// tRPC v11 HTTP wire format (no transformer):
    45→//   Query  : GET  /trpc/<procedure>            (no input = omit query param)
    46→//   Mutation: POST /trpc/<procedure>   body: <input as JSON>
    47→//   Response: {"result": {"data": <output>}}
    48→
    49→export interface TrpcResponse<T> {
    50→  result: { data: T };
    51→}
    52→
    53→// ─── API Client ───────────────────────────────────────────────────────────────
    54→
    55→/**
    56→ * API Client for Harmony backend.
    57→ * Handles JWT bearer auth, automatic token refresh on 401, and tRPC calls.
    58→ */
    59→class ApiClient {
    60→  private client: AxiosInstance;
    61→
    62→  constructor() {
    63→    this.client = axios.create({
    64→      baseURL: API_CONFIG.BASE_URL,
    65→      timeout: API_CONFIG.TIMEOUT,
    66→      headers: { 'Content-Type': 'application/json' },
    67→    });
    68→
    69→    this.setupInterceptors();
    70→  }
    71→
    72→  private setupInterceptors() {
    73→    // Request: attach Bearer token if present
    74→    this.client.interceptors.request.use(
    75→      (config: InternalAxiosRequestConfig) => {
    76→        const token = getAccessToken();
    77→        if (token) {
    78→          config.headers = config.headers ?? {};
    79→          config.headers.Authorization = `Bearer ${token}`;
    80→        }
    81→        return config;
    82→      },
    83→      error => Promise.reject(error),
    84→    );
    85→
    86→    // Response: on 401, attempt a silent token refresh then retry once
    87→    this.client.interceptors.response.use(
    88→      response => response,
    89→      async error => {
    90→        const originalRequest = error.config as InternalAxiosRequestConfig & { _retry?: boolean };
    91→
    92→        if (error.response?.status === 401 && !originalRequest._retry) {
    93→          const refreshToken = getRefreshToken();
    94→          if (!refreshToken) {
    95→            clearTokens();
    96→            return Promise.reject(error);
    97→          }
    98→
    99→          if (_isRefreshing) {
   100→            // Queue concurrent requests until the refresh completes
   101→            return new Promise(resolve => {
   102→              _refreshQueue.push((newToken: string | null) => {
   103→                if (newToken) {
   104→                  originalRequest.headers = originalRequest.headers ?? {};
   105→                  originalRequest.headers.Authorization = `Bearer ${newToken}`;
   106→                  resolve(this.client(originalRequest));
   107→                } else {
   108→                  resolve(Promise.reject(error));
   109→                }
   110→              });
   111→            });
   112→          }
   113→
   114→          originalRequest._retry = true;
   115→          _isRefreshing = true;
   116→
   117→          try {
   118→            const res = await axios.post<{ accessToken: string; refreshToken: string }>(
   119→              `${API_CONFIG.BASE_URL}/api/auth/refresh`,
   120→              { refreshToken },
   121→            );
   122→            const { accessToken: newAt, refreshToken: newRt } = res.data;
   123→            setTokens(newAt, newRt);
   124→            notifyRefreshQueue(newAt);
   125→
   126→            originalRequest.headers = originalRequest.headers ?? {};
   127→            originalRequest.headers.Authorization = `Bearer ${newAt}`;
   128→            return this.client(originalRequest);
   129→          } catch {
   130→            clearTokens();
   131→            notifyRefreshQueue(null);
   132→            if (typeof window !== 'undefined') {
   133→              window.location.href = '/auth/login';
   134→            }
   135→            return Promise.reject(error);
   136→          } finally {
   137→            _isRefreshing = false;
   138→          }
   139→        }
   140→
   141→        return Promise.reject(error);
   142→      },
   143→    );
   144→  }
   145→
   146→  async get<T>(url: string, config?: AxiosRequestConfig): Promise<T> {
   147→    const response = await this.client.get<T>(url, config);
   148→    return response.data;
   149→  }
   150→
   151→  async post<T>(url: string, data?: unknown, config?: AxiosRequestConfig): Promise<T> {
   152→    const response = await this.client.post<T>(url, data, config);
   153→    return response.data;
   154→  }
   155→
   156→  async put<T>(url: string, data?: unknown, config?: AxiosRequestConfig): Promise<T> {
   157→    const response = await this.client.put<T>(url, data, config);
   158→    return response.data;
   159→  }
   160→
   161→  async delete<T>(url: string, config?: AxiosRequestConfig): Promise<T> {
   162→    const response = await this.client.delete<T>(url, config);
   163→    return response.data;
   164→  }
   165→
   166→  /** Call a tRPC query procedure (GET). Returns the unwrapped data. */
   167→  async trpcQuery<T>(procedure: string): Promise<T> {
   168→    const res = await this.client.get<TrpcResponse<T>>(`/trpc/${procedure}`);
   169→    return res.data.result.data;
   170→  }
   171→
   172→  /** Call a tRPC mutation procedure (POST). Returns the unwrapped data. */
   173→  async trpcMutation<T>(procedure: string, input?: unknown): Promise<T> {
   174→    const res = await this.client.post<TrpcResponse<T>>(
   175→      `/trpc/${procedure}`,
   176→      input ?? null,
   177→    );
   178→    return res.data.result.data;
   179→  }
   180→}
