/**
 * Server Service (M1 — mock implementation)
 * References: dev-spec-channel-visibility-toggle.md
 */

import { cache } from 'react';
import type { Server, User, CreateServerInput } from '@/types';
import { mockServers, mockUsers } from '@/mocks';

// ─── In-memory store (mutated by write operations) ────────────────────────────

const g = globalThis as typeof globalThis & { __harmonyServers?: Server[] };
g.__harmonyServers ??= [...mockServers];
const servers: Server[] = g.__harmonyServers;

// ─── Service ──────────────────────────────────────────────────────────────────

/**
 * Returns all servers.
 */
export async function getServers(): Promise<Server[]> {
  return [...servers];
}

/**
 * Returns a single server by its slug, or null if not found.
 */
export const getServer = cache(async (slug: string): Promise<Server | null> => {
  return servers.find(s => s.slug === slug) ?? null;
});

/**
 * Returns all members (users) of a server by server ID.
 * In the mock layer, all users belong to every server for simplicity.
 */
export async function getServerMembers(_serverId: string): Promise<User[]> {
  // Simulate membership — real API would filter by _serverId
  return [...mockUsers];
}

/**
 * Updates editable metadata (name, description, icon) of a server in-memory.
 * slug is intentionally excluded — renaming the slug would break existing URLs.
 */
export async function updateServer(
  slug: string,
  patch: Partial<Pick<Server, 'name' | 'description' | 'icon'>>,
): Promise<Server> {
  const index = servers.findIndex(s => s.slug === slug);
  if (index === -1) {
    throw new Error(`Server not found: ${slug}`);
  }
  servers[index] = {
    ...servers[index],
    ...Object.fromEntries(Object.entries(patch).filter(([, v]) => v !== undefined)),
    updatedAt: new Date().toISOString(),
  };
  return { ...servers[index] };
}

/**
 * Deletes a server by slug. Returns true if deleted, false if not found.
 */
export async function deleteServer(slug: string): Promise<boolean> {
  const index = servers.findIndex(s => s.slug === slug);
  if (index === -1) return false;
  servers.splice(index, 1);
  return true;
}

/**
 * Creates a new server and appends it to the in-memory store.
 */
export async function createServer(input: CreateServerInput): Promise<Server> {
  const slug = input.name
    .toLowerCase()
    .replace(/\s+/g, '-')
    .replace(/[^a-z0-9-]/g, '')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');

  const existing = servers.find(s => s.slug === slug);
  if (existing) {
    throw new Error('A server with this name already exists.');
  }

  const newServer: Server = {
    id: `server-${Date.now()}`,
    name: input.name.trim(),
    slug,
    ownerId: 'user-001',
    description: input.description?.trim() ?? '',
    memberCount: 1,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };

  servers.push(newServer);
  return { ...newServer };
}

/**
 * GuestChannelView — simplified layout for anonymous public channel access.
 * No ServerRail, no ChannelSidebar, no MessageInput.
 * Wraps content in VisibilityGuard so PRIVATE channels show AccessDeniedPage.
 * Ref: dev-spec-guest-public-channel-view.md — M1, C1.1 PublicChannelPage
 */

import { notFound } from 'next/navigation';
import { getServer, getServerMembers } from '@/services/serverService';
import { getChannel } from '@/services/channelService';
import { getMessages } from '@/services/messageService';
import { AuthRedirect } from '@/components/channel/AuthRedirect';
import { VisibilityGuard } from '@/components/channel/VisibilityGuard';
import { MessageList } from '@/components/channel/MessageList';
import { GuestPromoBanner } from '@/components/channel/GuestPromoBanner';
import { ChannelVisibility } from '@/types';
import type { Server, Channel } from '@/types';

// ─── Guest Header ─────────────────────────────────────────────────────────────

function GuestHeader({ server, memberCount }: { server: Server; memberCount: number }) {
  return (
    <header className='flex h-14 shrink-0 items-center gap-3 border-b border-black/20 bg-[#2f3136] px-4'>
      {/* Harmony logo wordmark */}
      <span className='text-lg font-bold text-[#5865f2]'>Harmony</span>

      {/* Divider */}
      <span className='text-gray-600' aria-hidden='true'>
        /
      </span>

      {/* Server name */}
      <span className='text-sm font-semibold text-white'>{server.name}</span>

      {/* Member count */}
      <span className='ml-auto flex items-center gap-1.5 text-xs text-gray-400'>
        <svg
          className='h-3.5 w-3.5'
          viewBox='0 0 24 24'
          fill='currentColor'
          aria-hidden='true'
          focusable='false'
        >
          <path d='M16 11c1.66 0 2.99-1.34 2.99-3S17.66 5 16 5c-1.66 0-3 1.34-3 3s1.34 3 3 3zm-8 0c1.66 0 2.99-1.34 2.99-3S9.66 5 8 5C6.34 5 5 6.34 5 8s1.34 3 3 3zm0 2c-2.33 0-7 1.17-7 3.5V19h14v-2.5c0-2.33-4.67-3.5-7-3.5zm8 0c-.29 0-.62.02-.97.05 1.16.84 1.97 1.97 1.97 3.45V19h6v-2.5c0-2.33-4.67-3.5-7-3.5z' />
        </svg>
        {memberCount.toLocaleString()} members
      </span>
    </header>
  );
}

// ─── Channel Header ───────────────────────────────────────────────────────────

function ChannelHeader({ channel }: { channel: Channel }) {
  return (
    <div className='flex shrink-0 items-center gap-2 border-b border-black/20 bg-[#36393f] px-4 py-3'>
      <svg
        className='h-5 w-5 shrink-0 text-gray-400'
        viewBox='0 0 24 24'
        fill='currentColor'
        aria-hidden='true'
