     1→import { Router, Request, Response } from 'express';
     2→import { prisma } from '../db/prisma';
     3→import { ChannelVisibility } from '@prisma/client';
     4→import { cacheMiddleware } from '../middleware/cache.middleware';
     5→import { cacheService, CacheKeys, CacheTTL, sanitizeKeySegment } from '../services/cache.service';
     6→import { tokenBucketRateLimiter } from '../middleware/rate-limit.middleware';
     7→
     8→export const publicRouter = Router();
     9→
    10→// Token bucket rate limiting per issue #110: 100 req/min (human) / 1000 req/min (verified bots)
    11→publicRouter.use(tokenBucketRateLimiter);
    12→
    13→/**
    14→ * GET /api/public/channels/:channelId/messages
    15→ * Returns paginated messages for a PUBLIC_INDEXABLE channel.
    16→ * Uses cache middleware with stale-while-revalidate.
    17→ */
    18→publicRouter.get(
    19→  '/channels/:channelId/messages',
    20→  cacheMiddleware({
    21→    ttl: CacheTTL.channelMessages,
    22→    staleTtl: CacheTTL.channelMessages, // keep stale data for an extra TTL window
    23→    keyFn: (req: Request) => CacheKeys.channelMessages(req.params.channelId, Number(req.query.page) || 1),
    24→  }),
    25→  async (req: Request, res: Response) => {
    26→    try {
    27→      const { channelId } = req.params;
    28→      const page = Math.max(1, Number(req.query.page) || 1);
    29→      const pageSize = 50;
    30→
    31→      const channel = await prisma.channel.findUnique({
    32→        where: { id: channelId },
    33→        select: { id: true, visibility: true },
    34→      });
    35→
    36→      if (!channel || channel.visibility !== ChannelVisibility.PUBLIC_INDEXABLE) {
    37→        res.status(404).json({ error: 'Channel not found' });
    38→        return;
    39→      }
    40→
    41→      const messages = await prisma.message.findMany({
    42→        where: { channelId, isDeleted: false },
    43→        orderBy: { createdAt: 'desc' },
    44→        skip: (page - 1) * pageSize,
    45→        take: pageSize,
    46→        select: {
    47→          id: true,
    48→          content: true,
    49→          createdAt: true,
    50→          editedAt: true,
    51→          author: { select: { id: true, username: true } },
    52→        },
    53→      });
    54→
    55→      res.set('Cache-Control', `public, max-age=${CacheTTL.channelMessages}`);
    56→      res.json({ messages, page, pageSize });
    57→    } catch (err) {
    58→      console.error('Public messages route error:', err);
    59→      if (!res.headersSent) {
    60→        res.status(500).json({ error: 'Internal server error' });
    61→      }
    62→    }
    63→  },
    64→);
    65→
    66→/**
    67→ * GET /api/public/channels/:channelId/messages/:messageId
    68→ * Returns a single message from a PUBLIC_INDEXABLE channel.
    69→ * Uses cache middleware with stale-while-revalidate.
    70→ */
    71→publicRouter.get(
    72→  '/channels/:channelId/messages/:messageId',
    73→  cacheMiddleware({
    74→    ttl: CacheTTL.channelMessages,
    75→    staleTtl: CacheTTL.channelMessages,
